import pytest

def zip_dicts(*dicts) -> dict:
    keys = set().union(*dicts)
    return {k: [d.get(k) for d in dicts] for k in keys}

def test_zip_dicts_happy_path():
    d1 = {'a': 1, 'b': 2}
    d2 = {'a': 3, 'b': 4, 'c': 5}
    d3 = {'a': 6, 'c': 7, 'd': 8}

    result = zip_dicts(d1, d2, d3)

    assert result == {
        'a': [1, 3, 6],
        'b': [2, 4, None],
        'c': [None, 5, 7],
        'd': [None, None, 8]
    }

def test_zip_dicts_empty_dicts():
    d1 = {}
    d2 = {}
    d3 = {}

    result = zip_dicts(d1, d2, d3)

    assert result == {}

def test_zip_dicts_single_dict():
    d1 = {'a': 1, 'b': 2}

    result = zip_dicts(d1)

    assert result == {'a': [1], 'b': [2]}

def test_zip_dicts_no_dicts():
    result = zip_dicts()

    assert result == {}

def test_zip_dicts_some_dicts_empty():
    d1 = {'a': 1, 'b': 2}
    d2 = {}
    d3 = {'a': 3, 'c': 4}

    result = zip_dicts(d1, d2, d3)

    assert result == {
        'a': [1, None, 3],
        'b': [2, None, None],
        'c': [None, None, 4]
    }

def test_zip_dicts_dicts_with_different_keys():
    d1 = {'a': 1, 'b': 2}
    d2 = {'c': 3, 'd': 4}
    d3 = {'e': 5, 'f': 6}

    result = zip_dicts(d1, d2, d3)

    assert result == {
        'a': [1, None, None],
        'b': [2, None, None],
        'c': [None, 3, None],
        'd': [None, 4, None],
        'e': [None, None, 5],
        'f': [None, None, 6]
    }

def test_zip_dicts_dicts_with_none_values():
    d1 = {'a': 1, 'b': None}
    d2 = {'a': None, 'b': 2}
    d3 = {'a': 3, 'b': None}

    result = zip_dicts(d1, d2, d3)

    assert result == {
        'a': [1, None, 3],
        'b': [None, 2, None]
    }

def test_zip_dicts_dicts_with_mixed_types():
    d1 = {'a': 1, 'b': 'two'}
    d2 = {'a': 3.0, 'b': 4}
    d3 = {'a': 'three', 'b': 5.0}

    result = zip_dicts(d1, d2, d3)

    assert result == {
        'a': [1, 3.0, 'three'],
        'b': ['two', 4, 5.0]
    }

if __name__ == "__main__":
    pytest.main()
```

